#include <bits/stdc++.h>using namespace std;typedef long long ll; void solve() {    int n;    cin >> n;     vector<ll> a(n);    for (auto &x : a) cin >> x;        for (int i = 0; i < n; i++) {        ll x; cin >> x;    }     int ct = 0;    for (int i = 0; i < n; i++) {        ll l, r;    if (i > 0) {            l = __gcd(a[i - 1], a[i]);        } else {            l = 1;        }         if (i < n - 1) {            r = __gcd(a[i], a[i + 1]);        } else {            r = 1;        }        ll m = (l / __gcd(l, r)) * r;         if (m < a[i]) {            ct++;        }    }    cout << ct << "\n";} int main() {    ios::sync_with_stdio(0);    cin.tie(0);     int t;    cin >> t;    while (t--) solve();     return 0;}